  import java.util.StringTokenizer;
  import sailpoint.object.Identity;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  
  

  /*Start below */
  Log logger = LogFactory.getLog("Ascension-Rule-Correlation-ServiceNow");
  
  Map map = new HashMap();
  String correlatedIdentityName = "";
  boolean isFound = false;

  Iterator itr = null;
  

  String employeeId = (String) account.getAttribute("employee_number");
  String internalId = (String) account.getAttribute("u_sailpoint_id");
  String samAccountName =(String) account.getAttribute("user_name");
  String email = (String) account.getAttribute("email");
  
 
  // search with iiq employeeId = employee_number app
  if(!isFound && Util.isNotNullOrEmpty(employeeId)){
    correlatedIdentityName = getIdentityNameByProperty("employeeId", employeeId);
    if( Util.isNotNullOrEmpty(correlatedIdentityName) ){
      isFound = true;
    }
  }
 

  //search with iiq internalId = u_sailpoint_id app
  if(!isFound && Util.isNotNullOrEmpty(internalId)){
    //correlatedIdentityName = getIdentityNameByProperty("internalId", internalId);
	map = findInternalIdBasedCorrelationMap(internalId);
    if(!map.isEmpty()){
      isFound = true;
    }
  }
  

  //search with iiq samAccountName = user_name app
  if(!isFound && Util.isNotNullOrEmpty(samAccountName)){
    samAccountName = getSamAccountNameFromPrincipalName(samAccountName);

    correlatedIdentityName = getIdentityNameByProperty("samAccountName", samAccountName);

    if( Util.isNotNullOrEmpty(correlatedIdentityName) ){
      isFound = true;
    }

  }

  

  //search with iiq email = email app
  if(!isFound && Util.isNotNullOrEmpty(email)){
    correlatedIdentityName = getIdentityNameByProperty("email", email);
    if( Util.isNotNullOrEmpty(correlatedIdentityName) ){
      isFound = true;
    }
  }


  // check child
  if(isFound && Util.isNotNullOrEmpty(correlatedIdentityName)){

    String tempName = getPrimaryIdentityNameByName(correlatedIdentityName);
    if(Util.isNotNullOrEmpty(tempName)){
      correlatedIdentityName = tempName;
    }
  }
  
  if(map.isEmpty()){
	map.put("identityName", correlatedIdentityName);
  }
  return map;
